//refAssemblies: TCAdmin.SDK.dll, TCAdmin.Docker.SDK.dll, TCAdmin.Scripting.dll, TCAdmin.Scripting.SDK.dll, TCAdmin.Monitor.dll
using System;
using System.Threading.Tasks;
using TCAdmin.SDK.Database.Entities;
using TCAdmin.SDK.DynamicInput.Controls;

var Globals = new TCAdmin.Scripting.Engines.Addons.CSharpDockerGlobals(); // DO NOT MODIFY THIS LINE
var console = Globals.ScriptConsole;
var service = Globals.ThisService;

var oldName = service.Name ?? "";

// Prompt the user for the new name (dialog is prefilled with the current name).
// Dynamic values are passed to WriteLine as {0} args — the console runs string.Format,
// so a name containing '{' would otherwise throw.
var input = await Globals.ThisScript.Input(new DynamicTextBox
{
    Id = "name",
    Label = "New service name",
    Description = "Enter the new name for this service.",
    DefaultValue = oldName,
    Required = true
});

if (input.Canceled)
{
    console.WriteLine("↩️  Cancelled — the service name was not changed.");
    return;
}

var newName = (input.Values["name"]?.ToString() ?? "").Trim();
if (newName.Length == 0)
{
    console.WriteLine("❌  The name cannot be empty. No change was made.");
    return;
}

if (string.Equals(newName, oldName, StringComparison.Ordinal))
{
    console.WriteLine("ℹ️  The name is unchanged. Nothing to do.");
    return;
}

// Load the service tracked in the manager's own scope and mutate THAT instance
// (updating the cached Globals.ThisService would be a detached write and is rejected).
var manager = Globals.DockerServiceManager;
var tracked = await manager.GetAsync(service.ServiceId);
if (tracked == null)
{
    console.WriteLine("❌  Could not load service id {0}.", service.ServiceId);
    return;
}

tracked.Name = newName;
await manager.UpdateAsync(tracked, saveChanges: true);

console.WriteLine("✅  Service name updated.");
console.WriteLine("   From : {0}", oldName);
console.WriteLine("   To   : {0}", newName);

//refAssemblies: TCAdmin.SDK.dll, TCAdmin.Docker.SDK.dll, TCAdmin.Web.Shared.dll, TCAdmin.Scripting.dll, TCAdmin.Monitor.dll
using System;
using System.IO;
using System.Threading.Tasks;
using TCAdmin.SDK.Database.Entities;

var Globals = new TCAdmin.Scripting.Engines.Addons.CSharpDockerGlobals(); // DO NOT MODIFY THIS LINE
var console = Globals.ScriptConsole;
var service = Globals.ThisService;

// NOTE: IScriptConsole.WriteLine(string, params) runs string.Format on the string, so
// any literal { } would throw. Dynamic values are passed as {0} args (never concatenated
// into the format string) so paths/templates containing ${...} print safely.
console.WriteLine("🚀  Enabling Fast Downloads for this server...");
console.WriteLine();

// nginx serves {RootDirectory}/www at its web root. Fast Download files live in a
// dedicated /FastDL sub-folder (kept separate from the landing page), and the public
// URL carries the same /FastDL segment so it maps 1:1 onto the files on disk.
var fastDlPath = Path.Combine(service.RootDirectory, "www", "FastDL");

// Public HTTPS endpoint = HostnameOrIP + the allocated 'HTTPS' host port + /FastDL.
var httpsPort = service.Ports["HTTPS"]; // safe indexer -> 0 when the key is missing
if (httpsPort <= 0)
{
    console.WriteLine("❌  This service has no allocated 'HTTPS' port.");
    console.WriteLine("     Add an 'HTTPS' custom port to the blueprint, then recreate the service.");
    return;
}

var host = service.HostnameOrIP; // hostname if the IP has one, otherwise the IP
if (string.IsNullOrWhiteSpace(host))
{
    console.WriteLine("❌  Could not determine the service address.");
    return;
}

var baseUrl = "https://" + host + ":" + httpsPort + "/FastDL/";

// Create the storage folder if it doesn't exist (as the monitor process, the same way
// the FastDL sync engine creates its own sub-directories).
try
{
    Directory.CreateDirectory(fastDlPath);
}
catch (Exception ex)
{
    console.WriteLine("⚠️  Could not create the FastDL folder ({0}): {1}", fastDlPath, ex.Message);
    console.WriteLine("     Continuing — the sync engine will create it on first run.");
}

// Load the Server tracked in the manager's own scope and mutate THAT instance.
// (Updating the cached Globals.ThisServer would be a detached write and is rejected.)
var serverManager = Globals.ServerManager;
var server = await serverManager.GetAsync(service.ServerId);
if (server == null)
{
    console.WriteLine("❌  Could not load server id {0}.", service.ServerId);
    return;
}

server.FastDLEnabled = true;
server.FastDLPath = fastDlPath;
server.FastDLBaseUrl = baseUrl;
await serverManager.UpdateAsync(server, saveChanges: true);

console.WriteLine("✅  Fast Downloads enabled!");
console.WriteLine();
console.WriteLine("🖥️   Server      : {0}", server.Name);
console.WriteLine("📁  Storage     : {0}", fastDlPath);
console.WriteLine("🔗  Base URL    : {0}", baseUrl);
console.WriteLine("🗂️   Per-service : {0}", server.FastDLFolderTemplate);
console.WriteLine();
console.WriteLine("⚠️   Fast Downloads are now enabled on this SERVER — but they must ALSO be");
console.WriteLine("     enabled and configured for each individual game before its services");
console.WriteLine("     will mirror and serve their files here.");
console.WriteLine("🎉  All done!");

//refAssemblies: TCAdmin.SDK.dll, TCAdmin.Docker.SDK.dll, TCAdmin.Web.Shared.dll, TCAdmin.Scripting.dll, TCAdmin.Monitor.dll
using System;
using System.IO;
using System.Threading.Tasks;
using TCAdmin.SDK.Database.Entities;

var Globals = new TCAdmin.Scripting.Engines.Addons.CSharpDockerGlobals(); // DO NOT MODIFY THIS LINE
var console = Globals.ScriptConsole;
var service = Globals.ThisService;

// The folder this service's nginx container served Fast Downloads from. Must match the
// path the enable icon writes ({RootDirectory}/www/FastDL) so the guard below can detect it.
var fastDlPath = Path.Combine(service.RootDirectory, "www", "FastDL");

var serverManager = Globals.ServerManager;
var server = await serverManager.GetAsync(service.ServerId);
if (server == null)
{
    // WriteLine uses {0} args (not concatenation) because the console runs string.Format.
    console.WriteLine("⚠️  Could not load server id {0}; nothing to clean up.", service.ServerId);
    return;
}

// Only clear the server-level Fast Download settings if THIS service is the one currently
// backing them (enabled + storage path points at this service's /FastDL). Separator/
// trailing-slash tolerant and case-insensitive, so a second nginx service deleting doesn't
// wipe the config a different one owns.
var currentPath = (server.FastDLPath ?? "").Replace('\\', '/').TrimEnd('/');
var thisPath = (fastDlPath ?? "").Replace('\\', '/').TrimEnd('/');

if (server.FastDLEnabled && string.Equals(currentPath, thisPath, StringComparison.OrdinalIgnoreCase))
{
    server.FastDLEnabled = false;
    server.FastDLPath = "";
    server.FastDLBaseUrl = "";
    await serverManager.UpdateAsync(server, saveChanges: true);

    console.WriteLine("🧹  Fast Downloads disabled on server '{0}'.", server.Name);
    console.WriteLine("     Storage path and base URL cleared.");
}
else
{
    console.WriteLine("ℹ️  Server Fast Downloads are not pointing at this service — left unchanged.");
}

//refAssemblies: TCAdmin.SDK.dll, TCAdmin.Docker.SDK.dll, TCAdmin.Scripting.dll, TCAdmin.Monitor.dll, Docker.DotNet.dll, System.Security.Cryptography.dll, System.Net.Primitives.dll
using System;
using System.IO;
using System.Text;
using System.Collections.Generic;
using System.Security.Cryptography;
using System.Security.Cryptography.X509Certificates;
using Docker.DotNet.Models;

var Globals = new TCAdmin.Scripting.Engines.Addons.CSharpDockerGlobals(); // DO NOT MODIFY THIS LINE
var service = Globals.ThisService;
var startParams = Globals.ThisContainerStartParameters;

// ---------------------------------------------------------------------------
// Paths are built from the service root dir, exactly like TCAdmin's own volume
// binds (Path.Combine(service.RootDirectory, ...)), so this works whether the
// Docker host is Linux or Windows.
// ---------------------------------------------------------------------------
var sslDir = Path.Combine(service.RootDirectory, "nginx", "ssl");
var confDir = Path.Combine(service.RootDirectory, "nginx", "conf.d");
var wwwDir = Path.Combine(service.RootDirectory, "www");
Directory.CreateDirectory(sslDir);
Directory.CreateDirectory(confDir);
Directory.CreateDirectory(wwwDir);

var crtPath = Path.Combine(sslDir, "server.crt");
var keyPath = Path.Combine(sslDir, "server.key");
var confPath = Path.Combine(confDir, "default.conf");

// Address clients will connect to (used for the cert subject / SAN).
var host = service.IPAddress;
if (string.IsNullOrWhiteSpace(host)) { host = "localhost"; }

// DER bytes -> PEM text (fixed LF line endings, cross-platform).
Func<string, byte[], string> toPem = (label, der) =>
{
    var b64 = Convert.ToBase64String(der);
    var sb = new StringBuilder();
    sb.Append("-----BEGIN ").Append(label).Append("-----\n");
    for (int i = 0; i < b64.Length; i += 64)
    {
        sb.Append(b64.Substring(i, Math.Min(64, b64.Length - i))).Append('\n');
    }
    sb.Append("-----END ").Append(label).Append("-----\n");
    return sb.ToString();
};

// ---------------------------------------------------------------------------
// Generate a self-signed certificate once (idempotent). Pure .NET crypto, so
// no openssl and no container internet access are required.
// ---------------------------------------------------------------------------
if (!File.Exists(crtPath) || !File.Exists(keyPath))
{
    using (var rsa = RSA.Create(2048))
    {
        var req = new CertificateRequest("CN=" + host, rsa, HashAlgorithmName.SHA256, RSASignaturePadding.Pkcs1);
        req.CertificateExtensions.Add(new X509BasicConstraintsExtension(false, false, 0, false));
        req.CertificateExtensions.Add(new X509KeyUsageExtension(
            X509KeyUsageFlags.DigitalSignature | X509KeyUsageFlags.KeyEncipherment, false));
        req.CertificateExtensions.Add(new X509EnhancedKeyUsageExtension(
            new OidCollection { new Oid("1.3.6.1.5.5.7.3.1") }, false)); // serverAuth

        var san = new SubjectAlternativeNameBuilder();
        san.AddDnsName(host);
        System.Net.IPAddress ip;
        if (System.Net.IPAddress.TryParse(host, out ip)) { san.AddIpAddress(ip); }
        req.CertificateExtensions.Add(san.Build());

        using (var cert = req.CreateSelfSigned(
            DateTimeOffset.UtcNow.AddDays(-1), DateTimeOffset.UtcNow.AddYears(10)))
        {
            File.WriteAllText(crtPath, toPem("CERTIFICATE", cert.Export(X509ContentType.Cert)));
            File.WriteAllText(keyPath, toPem("PRIVATE KEY", rsa.ExportPkcs8PrivateKey()));
        }
    }

    // Private key should not be world-readable (no-op / unsupported on Windows).
    if (!System.OperatingSystem.IsWindows())
    {
        try { File.SetUnixFileMode(keyPath, UnixFileMode.UserRead | UnixFileMode.UserWrite); } catch { }
    }
}

// ---------------------------------------------------------------------------
// nginx config: keep HTTP (:80) and add HTTPS (:443) using the self-signed cert.
// Written on every start (static / idempotent). Mounted read-only over the
// image's default.conf.
// ---------------------------------------------------------------------------
var conf =
    "server {\n" +
    "    listen       80;\n" +
    "    server_name  _;\n" +
    "    location / {\n" +
    "        root   /usr/share/nginx/html;\n" +
    "        index  index.html index.htm;\n" +
    "    }\n" +
    "    error_page   500 502 503 504  /50x.html;\n" +
    "    location = /50x.html { root /usr/share/nginx/html; }\n" +
    "}\n" +
    "\n" +
    "server {\n" +
    "    listen       443 ssl;\n" +
    "    http2        on;\n" +
    "    server_name  _;\n" +
    "\n" +
    "    ssl_certificate      /etc/nginx/ssl/server.crt;\n" +
    "    ssl_certificate_key  /etc/nginx/ssl/server.key;\n" +
    "    ssl_protocols        TLSv1.2 TLSv1.3;\n" +
    "    ssl_ciphers          HIGH:!aNULL:!MD5;\n" +
    "    ssl_session_cache    shared:SSL:10m;\n" +
    "    ssl_session_timeout  10m;\n" +
    "\n" +
    "    location / {\n" +
    "        root   /usr/share/nginx/html;\n" +
    "        index  index.html index.htm;\n" +
    "    }\n" +
    "    error_page   500 502 503 504  /50x.html;\n" +
    "    location = /50x.html { root /usr/share/nginx/html; }\n" +
    "}\n";
File.WriteAllText(confPath, conf);

// Note: www/index.html is NOT seeded here — it is a blueprint config-file template
// (managed via the panel / Blueprint ConfigFiles API), which is the single source of
// truth and is applied to the service on setup. Seeding it here would be dead code.

// ---------------------------------------------------------------------------
// Bind-mount the config + cert into the container. The files exist by now
// because this ConfigureContainer script runs before the container is created.
// ---------------------------------------------------------------------------
startParams.HostConfig ??= new HostConfig();
startParams.HostConfig.Mounts ??= new List<Mount>();
startParams.HostConfig.Mounts.Add(new Mount { Type = "bind", Source = confPath, Target = "/etc/nginx/conf.d/default.conf", ReadOnly = true });
startParams.HostConfig.Mounts.Add(new Mount { Type = "bind", Source = crtPath, Target = "/etc/nginx/ssl/server.crt", ReadOnly = true });
startParams.HostConfig.Mounts.Add(new Mount { Type = "bind", Source = keyPath, Target = "/etc/nginx/ssl/server.key", ReadOnly = true });
